args.cypher:
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE EXISTS {
  MATCH (sm)-[:HAS_ELEMENT*]->(prop:Property)
  WHERE toLower(prop.value) CONTAINS 'hall 4' OR prop.value CONTAINS 'Hall 4'
}
   OR EXISTS {
  MATCH (aas)-[:HAS_DESCRIPTION]->(ls:LangString)
  WHERE toLower(ls.text) CONTAINS 'hall 4'
}
RETURN DISTINCT aas.idShort AS device_id_short, aas.id AS aas_id, 
       aas.category AS category
